import{_ as e,o as r,c as d,ag as a}from"./chunks/framework.OsDJF_Ea.js";const o="/docs/modules/spectral-gate.png",u=JSON.parse('{"title":"Spectral Gate","description":"","frontmatter":{},"headers":[],"relativePath":"modules/spectral-gate.md","filePath":"modules/spectral-gate.md"}'),n={name:"modules/spectral-gate.md"};function s(i,t,c,g,l,h){return r(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="spectral-gate" tabindex="-1">Spectral Gate <a class="header-anchor" href="#spectral-gate" aria-label="Permalink to &quot;Spectral Gate&quot;">​</a></h1><p><strong>Category:</strong> Granular</p><p>Frequency-selective sidechain gate with granular scatter. Two inputs: a source and an exciter. The source is optionally band-filtered, then gated or scattered by transients on the exciter. At <code>scatter=0</code> it behaves as a clean sidechain gate. At <code>scatter=1</code> exciter transients trigger grains drawn from a 2-second source buffer. The band filter isolates a frequency range so only that band is affected -- the rest of the source passes through clean. Band frequency is CV-controllable for sweeping or keyboard tracking.</p><img src="'+o+'" alt="spectral-gate module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>1L</strong> (audio)</td><td>Source left -- the sample, recording, or sound you want to gate or granulate.</td></tr><tr><td><strong>1R</strong> (audio)</td><td>Source right.</td></tr><tr><td><strong>2L</strong> (audio)</td><td>Exciter left -- the sidechain signal that triggers gating or grains (e.g. a contact mic, drum loop).</td></tr><tr><td><strong>2R</strong> (audio)</td><td>Exciter right.</td></tr><tr><td><strong>gate_sensitivity</strong></td><td>Onset / gate threshold 0-1. Lower values trigger from quieter exciter transients.</td></tr><tr><td><strong>scatter</strong></td><td>0 = clean sidechain gate, 1 = full granular. Blends between the two.</td></tr><tr><td><strong>band_freq</strong></td><td>Target band centre frequency in Hz. 0 = fullband (no filter). CV: 0-1 maps 20Hz-10kHz exponentially.</td></tr><tr><td><strong>band_q</strong></td><td>Band filter width. 0.5 = wide, 5 = narrow / resonant.</td></tr><tr><td><strong>grain_density</strong></td><td>Base grain rate. 0 = trigger-only (grains only fire from exciter onsets).</td></tr><tr><td><strong>grain_size_ms</strong></td><td>Grain duration 5-500ms.</td></tr><tr><td><strong>position</strong></td><td>Read position in the source buffer 0-1.</td></tr><tr><td><strong>position_spread</strong></td><td>Random position offset per grain.</td></tr><tr><td><strong>pitch</strong></td><td>Pitch shift in semitones.</td></tr><tr><td><strong>pitch_spread</strong></td><td>Random pitch variation per grain.</td></tr><tr><td><strong>feedback</strong></td><td>Grain output fed back into the source buffer 0-0.95.</td></tr><tr><td><strong>dry_wet</strong></td><td>Dry source vs processed output.</td></tr><tr><td><strong>exciter_mix</strong></td><td>Exciter audio bleed into the output 0-1.</td></tr><tr><td><strong>freeze</strong></td><td>Freeze source buffer (stops recording new audio into it).</td></tr><tr><td><strong>stereo_width</strong></td><td>Stereo spread of grains.</td></tr><tr><td><strong>cloud_pan</strong></td><td>Overall pan offset.</td></tr><tr><td><strong>trigger</strong></td><td>External trigger CV (rising edge), independent of the exciter onset detector.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>outL</strong> (audio)</td><td>Left output.</td></tr><tr><td><strong>outR</strong> (audio)</td><td>Right output.</td></tr></tbody></table><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>sensitivity</code></td><td>0.3</td><td>Gate threshold sensitivity.</td></tr><tr><td><code>scatter</code></td><td>0.0</td><td>Granular scatter blend 0-1.</td></tr><tr><td><code>band_freq</code></td><td>0.0</td><td>Band centre frequency in Hz. 0 = fullband.</td></tr><tr><td><code>band_q</code></td><td>1.0</td><td>Band filter Q.</td></tr><tr><td><code>grain_density</code></td><td>0.0</td><td>Grain rate per second.</td></tr><tr><td><code>grain_size_ms</code></td><td>80.0</td><td>Grain duration.</td></tr><tr><td><code>position</code></td><td>0.3</td><td>Playback position 0-1.</td></tr><tr><td><code>position_spread</code></td><td>0.1</td><td>Random position offset.</td></tr><tr><td><code>pitch</code></td><td>0.0</td><td>Pitch shift in semitones.</td></tr><tr><td><code>pitch_spread</code></td><td>0.0</td><td>Random pitch variation.</td></tr><tr><td><code>feedback</code></td><td>0.0</td><td>Feedback amount 0-0.95.</td></tr><tr><td><code>dry_wet</code></td><td>1.0</td><td>Dry/wet blend.</td></tr><tr><td><code>exciter_mix</code></td><td>0.0</td><td>Exciter bleed 0-1.</td></tr><tr><td><code>freeze</code></td><td>0.0</td><td>Freeze state.</td></tr><tr><td><code>stereo_width</code></td><td>0.5</td><td>Stereo spread.</td></tr><tr><td><code>cloud_pan</code></td><td>0.5</td><td>Cloud pan position.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p><strong>Sidechain gate:</strong> <code>scatter=0</code>, <code>band_freq=0</code> (fullband). Connect a drum loop to the exciter to gate a pad. <strong>Frequency-selective gate:</strong> set <code>band_freq</code> to isolate a range; the rest of the source passes through clean. <strong>Spectral sweep:</strong> connect an LFO to <code>band_freq</code> CV. <strong>Keyboard tracking:</strong> connect a MIDI pitch CV to <code>band_freq</code> to track notes. <strong>Granular transplant:</strong> <code>scatter=1</code>, <code>grain_density=0</code>, connect a contact mic as the exciter -- each strike pulls a grain from the source.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',13)])])}const f=e(n,[["render",s]]);export{u as __pageData,f as default};
